'use client'

import { useMemo, useState } from 'react'
import Link from 'next/link'
import {
  AlertCircle, ArrowRight, BadgeCheck, BarChart3, Boxes, BriefcaseBusiness, Building2, CalendarClock,
  CheckCircle2, ChevronRight, CircleDollarSign, Clock3, Compass, Edit3, ExternalLink, Eye, Gauge,
  GitBranch, Globe2, GraduationCap, Handshake, Layers3, MapPin, Network, PackagePlus, Plus, RefreshCcw,
  Route, Search, ShieldAlert, ShieldCheck, Sparkles, Target, TrendingUp, TriangleAlert, UserRoundCog,
  UsersRound, WalletCards, Workflow,
} from 'lucide-react'
import type {
  RevenueTwinBusinessUnit, RevenueTwinEditableEntity, RevenueTwinSectionKey, RevenueTwinStatus,
  RevenueTwinValidationIssue,
} from '@/lib/revenue-command-os/types'
import { useDigitalTwin } from './DigitalTwinContext'
import DigitalTwinEntityDrawer from './DigitalTwinEntityDrawer'

function statusTone(status: string) {
  if (status === 'active' || status === 'validated' || status === 'available') return 'bg-emerald-50 text-emerald-700 ring-emerald-200'
  if (status === 'needs-validation' || status === 'conditional' || status === 'acknowledged') return 'bg-amber-50 text-amber-700 ring-amber-200'
  if (status === 'retired' || status === 'inactive' || status === 'unavailable') return 'bg-rose-50 text-rose-700 ring-rose-200'
  return 'bg-slate-100 text-slate-600 ring-slate-200'
}

function severityTone(severity: string) {
  if (severity === 'critical') return 'border-rose-200 bg-rose-50 text-rose-700'
  if (severity === 'high') return 'border-orange-200 bg-orange-50 text-orange-700'
  if (severity === 'medium') return 'border-amber-200 bg-amber-50 text-amber-700'
  return 'border-blue-200 bg-blue-50 text-blue-700'
}

function StatusPill({ status }: { status: string }) {
  return <span className={`rounded-full px-2.5 py-1 text-[9px] font-black uppercase tracking-[.08em] ring-1 ${statusTone(status)}`}>{status}</span>
}

function ProgressBar({ value, label }: { value: number; label?: string }) {
  const color = value >= 90 ? 'bg-emerald-500' : value >= 70 ? 'bg-blue-600' : value >= 50 ? 'bg-amber-500' : 'bg-rose-500'
  return <div><div className="mb-1.5 flex items-center justify-between text-[10px] font-black text-slate-600"><span>{label}</span><span>{value}%</span></div><div className="h-2 overflow-hidden rounded-full bg-slate-100"><div className={`h-full rounded-full ${color}`} style={{ width: `${Math.max(2, value)}%` }} /></div></div>
}

function SectionHeader({ eyebrow, title, description, action }: { eyebrow: string; title: string; description: string; action?: React.ReactNode }) {
  return <div className="flex flex-col gap-4 lg:flex-row lg:items-end lg:justify-between"><div><p className="text-[10px] font-black uppercase tracking-[.18em] text-cyan-700">{eyebrow}</p><h2 className="mt-1 text-2xl font-black tracking-[-.025em] text-slate-950">{title}</h2><p className="mt-2 max-w-3xl text-sm leading-6 text-slate-500">{description}</p></div>{action}</div>
}

function MiniStat({ icon: Icon, label, value, detail, tone = 'blue' }: { icon: React.ElementType; label: string; value: string | number; detail: string; tone?: 'blue' | 'green' | 'amber' | 'rose' | 'violet' }) {
  const tones = { blue: 'bg-blue-50 text-blue-700', green: 'bg-emerald-50 text-emerald-700', amber: 'bg-amber-50 text-amber-700', rose: 'bg-rose-50 text-rose-700', violet: 'bg-violet-50 text-violet-700' }
  return <div className="rounded-[22px] border border-slate-200 bg-white p-4 shadow-[0_10px_30px_rgba(15,23,42,.035)]"><div className="flex items-start justify-between"><span className={`grid h-10 w-10 place-items-center rounded-xl ${tones[tone]}`}><Icon size={18} /></span><p className="text-2xl font-black tracking-tight text-slate-950">{value}</p></div><p className="mt-3 text-xs font-black text-slate-800">{label}</p><p className="mt-1 text-[11px] leading-5 text-slate-500">{detail}</p></div>
}

function AddButton({ label, onClick }: { label: string; onClick: () => void }) {
  return <button onClick={onClick} className="inline-flex items-center gap-2 rounded-2xl bg-slate-950 px-4 py-3 text-xs font-black text-white shadow-lg shadow-slate-900/15"><Plus size={16} /> {label}</button>
}

function asRecord(item: unknown) { return item as Record<string, unknown> }

